{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-reconnect-spec-plus-pump-update-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "summary": "当前围绕已选中的出口未连接流股、缺失进料规格以及泵出口压力目标异常这三类问题生成候选提案；其中仅对有直接诊断支撑的已选中流股与设备给出最小、可审查的局部 patch。",
  "answers": [
    {
      "summary": "针对 heater-outlet-93、feed-93 和 pump-14 生成了候选提案，分别覆盖下游连接占位、进料流量规格占位以及泵目标压力/效率的局部修正建议。",
      "issues": [
        {
          "title": "加热器出口流股当前无下游连接",
          "details": "heater-outlet-93 被诊断为未连接到任何下游消费者或导出端，当前快照也显示拓扑无效。",
          "citations": [
            "diag-1",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        },
        {
          "title": "泵入口进料缺少流量规格",
          "details": "feed-93 缺失流量规格，属于直接求解输入不足。",
          "citations": [
            "diag-2",
            "flowdoc-stream-1"
          ]
        },
        {
          "title": "泵出口压力目标低于入口压力且效率存在范围警告",
          "details": "pump-14 的 outlet_pressure_target_kpa=170 低于入口流股 pressure_kpa=210；同时 efficiency_percent=54 存在推荐范围外警告。",
          "citations": [
            "diag-3",
            "diag-4",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为加热器出口添加下游连接占位",
          "target": {
            "type": "stream",
            "id": "heater-outlet-93"
          },
          "rationale": "直接诊断指出该流股未连接，且快照显示 invalid_topology。由于当前请求中没有现成下游单元或导出端可据实指定，最小 patch 仅保留下游连接占位，等待人工确认目标对象。",
          "patch": {
            "connection_placeholder": {
              "stream_id": "heater-outlet-93",
              "missing_end": "target",
              "expected_connection": "downstream_consumer_or_export_sink",
              "note": "需要为该出口流股补充一个明确的下游消费者或导出端"
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为泵入口进料补充流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-93"
          },
          "rationale": "直接诊断说明 feed-93 缺失流量规格。当前证据不足以推断具体数值，因此仅建议增加可审查的规格占位。",
          "patch": {
            "spec_placeholders": [
              {
                "name": "flow_rate",
                "required": true,
                "unit_family": "flow",
                "note": "需由用户补充该进料的流量规格"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-stream-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "将泵出口压力目标调整为高于入口压力的待确认值",
          "target": {
            "type": "unit",
            "id": "pump-14"
          },
          "rationale": "直接诊断指出 pump-14 的出口压力目标低于入口压力。现有入口压力为 210 kPa，而当前目标为 170 kPa；为消除该矛盾，建议将 outlet_pressure_target_kpa 改为高于 210 kPa 的待确认值，而不在证据不足时指定具体数字。",
          "patch": {
            "parameter_placeholders": [
              {
                "name": "outlet_pressure_target_kpa",
                "constraint": "> 210",
                "reason": "必须高于入口流股 pressure_kpa=210 以满足泵升压方向"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "标记泵效率参数为待复核",
          "target": {
            "type": "unit",
            "id": "pump-14"
          },
          "rationale": "效率参数存在推荐范围外警告，但当前请求未提供明确推荐区间，故不建议擅自改值，仅增加待复核占位以便人工判断是否修正。",
          "patch": {
            "parameter_placeholders": [
              {
                "name": "efficiency_percent",
                "constraint": "review_recommended_operating_range",
                "current_value": 54,
                "reason": "当前值触发推荐范围外警告，但缺少可直接采用的目标区间"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-4",
            "flowdoc-unit-1"
          ]
        }
      ],
      "confidence": 0.88,
      "citations": [
        "diag-1",
        "diag-2",
        "diag-3",
        "diag-4",
        "flowdoc-stream-1",
        "flowdoc-stream-3",
        "flowdoc-unit-1",
        "snapshot-1"
      ]
    }
  ]
}
